/* ===================== CHAPTER 1: Forces & motion ===================== */
window.QBANK.push(
  { s:"Physics", topic:"1. Forces & motion", sub:"Definition", year:9, exam:true,
    q:`What name is given to a push, a pull or a twist acting on an object?`,
    a:`A force.`,
    e:`A force (lực) is simply a push, pull or twist. Forces can change an object's speed, direction or shape. Đơn vị của lực là newton (N).` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Units", year:9, exam:true,
    q:`State the unit of force and the symbol used for it.`,
    a:`The newton, symbol N.`,
    e:`Lực được đo bằng newton (N). Tên này đặt theo nhà khoa học Isaac Newton — em sẽ gặp lại ông ở phần "cause and effect".` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Friction", year:9, exam:true,
    q:`What name is given to the force between two surfaces that are touching, and how does it usually affect a moving object?`,
    a:`Friction; it slows things down.`,
    e:`Friction (ma sát) xuất hiện khi hai bề mặt cọ vào nhau. Nó thường làm vật chuyển động chậm lại, hoặc ngăn không cho vật bắt đầu chuyển động. Đó là lý do người ta dùng con lăn hoặc bánh xe để giảm ma sát.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Friction", year:9, exam:true,
    q:`State two ways of reducing the friction between two surfaces.`,
    a:`Use rollers or wheels; add a lubricant.`,
    e:`Giảm ma sát có thể bằng: dùng bánh xe/con lăn, làm bề mặt nhẵn hơn, hoặc bôi trơn (lubricant) như dầu mỡ. Ít ma sát hơn nên dễ kéo vật hơn.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Contact forces", year:9, exam:true,
    q:`What name is given to a force that needs the objects to be touching before it can act? Give one example.`,
    a:`A contact force, for example friction.`,
    e:`Contact force (lực tiếp xúc) chỉ tác dụng khi hai vật chạm nhau — ví dụ ma sát, lực kéo của dây, lực đẩy. Khác với lực không tiếp xúc như trọng lực hay từ lực.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Non-contact forces", year:9, exam:true,
    q:`Name the three non-contact forces studied in Year 9.`,
    a:`Gravity, magnetism and static electricity.`,
    e:`Lực không tiếp xúc (non-contact force) tác dụng từ xa, không cần chạm: trọng lực, từ lực và lực tĩnh điện. Mỗi loại tạo ra một "trường lực" (force field).` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Balanced forces", year:9, exam:true,
    q:`Two forces are equal in size but act in opposite directions. What name is given to this pair of forces?`,
    a:`Balanced forces.`,
    e:`Lực cân bằng (balanced) = bằng nhau về độ lớn nhưng ngược chiều. Khi đó vật đứng yên hoặc tiếp tục chuyển động với tốc độ không đổi.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Balanced forces", year:9, exam:true,
    q:`A sled is pulled forwards by a force equal in size to the friction acting on it. Describe its motion.`,
    a:`It moves at a constant speed.`,
    e:`Khi lực kéo bằng đúng lực ma sát, hai lực cân bằng (balanced) → xe trượt giữ nguyên tốc độ, không nhanh hơn cũng không chậm hơn.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Unbalanced forces", year:9, exam:true,
    q:`State two things that unbalanced forces can do to an object.`,
    a:`They can change its speed and change its direction.`,
    e:`Lực không cân bằng (unbalanced) làm vật thay đổi tốc độ, đổi hướng, hoặc đổi hình dạng (shape). Nói cách khác, nó làm thay đổi chuyển động của vật.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Resultant force", year:9, exam:true,
    q:`What name is given to the single overall force that results from all the forces acting on an object?`,
    a:`The resultant force.`,
    e:`Resultant force (hợp lực) là kết quả gộp của tất cả lực. Nếu hai lực ngược chiều, hợp lực = hiệu của chúng và hướng theo lực lớn hơn.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Resultant force", year:9, exam:true,
    q:`A box is pushed forwards with 50 N while friction pushes back with 20 N. Calculate the resultant force in newtons and state its direction.`,
    a:`30 N forwards.`,
    e:`Hai lực ngược chiều nên trừ nhau: 50 N − 20 N = 30 N. Hợp lực hướng theo lực lớn hơn → 30 N về phía trước, nên cái hộp tăng tốc.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Resultant force", year:9, exam:true,
    q:`Two people pull a rope in opposite directions, one with 120 N and one with 120 N. State the resultant force. Give your answer in newtons.`,
    a:`0 N.`,
    e:`120 N − 120 N = 0 N. Lực cân bằng (balanced) nên dây không chuyển động — đây chính là trò kéo co hòa nhau!` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Accelerate", year:9, exam:true,
    q:`What name is given to a change in the speed of an object?`,
    a:`Acceleration.`,
    e:`Acceleration (gia tốc / sự tăng tốc) nghĩa là thay đổi tốc độ. Khi hợp lực hướng tới trước lớn hơn lực cản, vật sẽ tăng tốc.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Drag", year:9, exam:true,
    q:`What name is given to the force that slows down objects moving through a fluid? Name its two forms.`,
    a:`Drag; its forms are air resistance and water resistance.`,
    e:`Drag (lực cản) làm chậm vật đang di chuyển trong chất lưu. Trong không khí gọi là air resistance, trong nước gọi là water resistance.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Drag", year:9, exam:true,
    q:`What happens to the size of the drag force on an object as its speed increases?`,
    a:`It increases.`,
    e:`Khi tốc độ tăng, lực cản (drag) cũng tăng. Lý do: càng đi nhanh, mỗi giây vật phải đẩy nhiều chất lưu (không khí hoặc nước) sang một bên hơn, nên lực cản chống lại nó lớn hơn. The faster the object moves, the more fluid it pushes aside each second, so the drag force grows. Đây là ý quan trọng để hiểu "vận tốc tới hạn".` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Upthrust", year:9, exam:true,
    q:`What name is given to the force that pushes things up in liquids and gases?`,
    a:`Upthrust.`,
    e:`Upthrust (lực đẩy nổi) là lực hướng lên do chất lỏng hoặc khí tác dụng. Nó giúp thuyền nổi trên nước.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Upthrust", year:9, exam:true,
    q:`A boat floats steadily on water. Its weight is 2000 N. What is the size of the upthrust acting on it?`,
    a:`2000 N.`,
    e:`Upthrust = 2000 N. Lý do: thuyền nổi yên một chỗ nên các lực tác dụng lên nó phải cân bằng (balanced). The boat is in equilibrium, so the upward upthrust must exactly balance the downward weight — that is why the upthrust equals 2000 N. Nếu upthrust nhỏ hơn trọng lượng, hợp lực hướng xuống và thuyền sẽ chìm.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Top speed", year:9, exam:true,
    q:`What name is given to the maximum constant speed a vehicle reaches when the driving force and the resistive force become balanced?`,
    a:`Top speed.`,
    e:`Tốc độ tối đa đó gọi là top speed. Lý do tàu buồm đạt được nó: khi tàu chạy nhanh hơn, lực cản của nước tăng dần. Đến một lúc lực cản nước bằng đúng lực đẩy của buồm → hai lực cân bằng (balanced) → hợp lực = 0 → tàu không tăng tốc thêm được nữa. As the ship speeds up, water resistance rises until it balances the forward force from the sails; the resultant force then becomes zero, so the ship can no longer accelerate and holds a steady top speed.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Terminal velocity", year:9, exam:true,
    q:`What name is given to the maximum constant speed reached by a falling object when air resistance balances its weight?`,
    a:`Terminal velocity.`,
    e:`Terminal velocity (vận tốc tới hạn) là tốc độ rơi tối đa. Lúc đó air resistance = weight, hai lực cân bằng nên vật rơi đều, không nhanh thêm.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Terminal velocity", year:9, exam:true,
    q:`A skydiver opens her parachute. What happens to her terminal velocity?`,
    a:`It decreases to a new, lower value.`,
    e:`Vận tốc tới hạn của cô ấy giảm xuống một giá trị mới, thấp hơn. Lý do: dù mở ra tạo diện tích lớn → air resistance (lực cản không khí) tăng mạnh, lớn hơn trọng lượng nên cô ấy chậm lại. When the parachute opens it greatly increases air resistance, which becomes bigger than her weight, so she slows down. Khi đã chậm đủ, air resistance lại cân bằng với weight ở một tốc độ thấp hơn → đó là terminal velocity mới, an toàn để tiếp đất.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Velocity", year:9, exam:true,
    q:`What name is given to the speed of an object in a particular direction?`,
    a:`Velocity.`,
    e:`Speed chỉ cho biết "nhanh bao nhiêu"; velocity (vận tốc) cho biết "nhanh bao nhiêu VÀ theo hướng nào". Velocity = speed + direction.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Application", year:9, exam:true,
    q:`A racing car has a higher top speed than a family car. Give two reasons why.`,
    a:`A more powerful engine and a streamlined shape.`,
    e:`Top speed phụ thuộc lực đẩy tối đa và lực cản. Xe đua có động cơ mạnh hơn (cho lực đẩy về phía trước lớn hơn) và thân xe khí động học (streamlined, giảm lực cản không khí) → chạy nhanh hơn.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Deform", year:9, exam:true,
    q:`What name is given to a change in the shape of an object caused by a force? Give one example.`,
    a:`Deformation; for example a hammer changing the shape of a metal horseshoe.`,
    e:`Deformation = sự làm đổi hình dạng (vật bị deformed). Lực có thể bẻ cong, kéo giãn hay nén vật. Ví dụ búa rèn đập móng ngựa, hay kéo giãn dây kim loại.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Word problem", year:9, exam:true,
    q:`Minh pushes a heavy crate with a force of 80 N. Friction acts against him with 95 N. Does the crate move?`,
    a:`No, it stays still.`,
    e:`Thùng không di chuyển — nó đứng yên. Lý do: lực ma sát 95 N lớn hơn lực đẩy 80 N. Friction (95 N) is bigger than the push (80 N), so the resultant force is 15 N backwards and the crate cannot start moving. Bạn Minh cần đẩy mạnh hơn 95 N thì thùng mới nhúc nhích. Cố lên Minh!` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Word problem", year:9, exam:true,
    q:`Lan rides her bicycle. The forward force from pedalling is 60 N and the total drag and friction is 60 N. What type of motion does she have?`,
    a:`Constant (steady) speed.`,
    e:`Bạn Lan đi với tốc độ không đổi (constant speed). Lý do: lực đạp về phía trước 60 N bằng đúng tổng lực cản 60 N → các lực cân bằng (balanced) → hợp lực = 0. When the forward force equals the resistive force, the resultant force is zero, so there is no acceleration and the speed stays the same. Muốn nhanh hơn, Lan phải đạp mạnh hơn để lực vượt qua 60 N.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Application", year:9, exam:true,
    q:`What ground condition makes a sled useful for moving heavy loads?`,
    a:`Snow on the ground.`,
    e:`Xe trượt (sled) chỉ hữu ích khi mặt đất phủ tuyết. Lý do: tuyết rất trơn nên ma sát (friction) giữa xe trượt và mặt đất rất nhỏ → cần lực kéo nhỏ. Snow is slippery and greatly reduces the friction between the sled and the ground, so only a small pulling force is needed. Trên đất trơ không có tuyết, ma sát lớn → kéo xe trượt rất nặng.` }
);

/* ----- CLUSTER 1: Forces & gravity (Newton's 3rd law / action-reaction) ----- */
const PHX_FORCES = { title:`Forces, gravity and Newton's third law`, html:`<p>When an apple is held on a branch, two main forces act on it. Gravity pulls the apple downwards towards the centre of the Earth, while the branch holds it up with an equal upward force. The downward pull of gravity on the apple is called its weight, and it is measured in newtons. When the stem breaks, the upward force disappears, so the forces become unbalanced and the apple accelerates towards the ground. Sir Isaac Newton noticed that forces always act in pairs: if one object pushes or pulls a second object, the second object pushes or pulls back with a force that is equal in size but opposite in direction.</p><p><i>[Figure: an apple on a branch with two labelled arrows — a downward arrow labelled "weight" and an upward arrow of equal length from the branch; a second small diagram shows the apple falling with only the downward arrow remaining.]</i></p>` };
window.QBANK.push(
  { s:"Physics", topic:"1. Forces & motion", sub:"Passage", year:9, exam:true, p:PHX_FORCES,
    q:`Name the force pulling the apple towards the ground.`,
    a:`Gravity.`,
    e:`Lực kéo táo xuống là trọng lực (gravity). Lực hút đó tác dụng lên quả táo gọi là trọng lượng (weight), đo bằng newton.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Passage", year:9, exam:true, p:PHX_FORCES,
    q:`Using the passage, what name is given to the pair of forces on the apple after the stem breaks?`,
    a:`Unbalanced forces.`,
    e:`Sau khi cuống gãy, các lực tác dụng lên quả táo là lực không cân bằng (unbalanced forces). Lý do: khi còn trên cành, lực đỡ hướng lên của cành cân bằng với trọng lượng hướng xuống → vật đứng yên. When the stem breaks, the upward force from the branch disappears, so the forces become unbalanced; the resultant force now points downwards and the apple accelerates towards the ground.` },
  { s:"Physics", topic:"1. Forces & motion", sub:"Passage", year:9, exam:true, p:PHX_FORCES,
    q:`The passage says forces act in pairs. State what Newton's third law tells you about the force a hand feels when it pushes on a wall.`,
    a:`The wall pushes back with an equal and opposite force.`,
    e:`Định luật 3 Newton: lực luôn theo cặp. Tay đẩy tường thì tường đẩy lại tay với lực bằng độ lớn nhưng ngược chiều — đó là cặp lực phản lực (action-reaction).` }
);

/* ===================== CHAPTER 2: Energy ===================== */
window.QBANK.push(
  { s:"Physics", topic:"2. Energy", sub:"Energy stores", year:9, exam:true,
    q:`What name is given to the store of energy that all moving objects have?`,
    a:`Kinetic energy.`,
    e:`Kinetic energy (động năng) là năng lượng của vật đang chuyển động. Bất cứ thứ gì đang di chuyển — xe, gió, dòng nước — đều có động năng.` },
  { s:"Physics", topic:"2. Energy", sub:"Energy stores", year:9, exam:true,
    q:`Write down three examples of substances or objects that are stores of chemical energy.`,
    a:`Food, fuel and batteries.`,
    e:`Chemical energy (hóa năng) là năng lượng tích trong chất hóa học. Thức ăn, nhiên liệu (xăng, than) và pin đều lưu trữ hóa năng.` },
  { s:"Physics", topic:"2. Energy", sub:"Energy stores", year:9, exam:true,
    q:`What name is given to energy stored in raised objects that can fall down?`,
    a:`Gravitational potential energy.`,
    e:`Gravitational potential energy — GPE (thế năng hấp dẫn) — là năng lượng của vật ở trên cao. Khi vật rơi xuống, GPE chuyển thành động năng.` },
  { s:"Physics", topic:"2. Energy", sub:"Energy stores", year:9, exam:true,
    q:`What name is given to energy stored in stretched or squashed objects? State another name for it.`,
    a:`Elastic potential energy (strain energy).`,
    e:`Elastic potential energy (thế năng đàn hồi), còn gọi là strain energy, là năng lượng trong vật bị kéo giãn hoặc nén — như lò xo cuốn hay cung tên kéo căng.` },
  { s:"Physics", topic:"2. Energy", sub:"Energy stores", year:9, exam:true,
    q:`An archer pulls back a bow before shooting an arrow. Name the store of energy in the stretched bow, and state what it becomes when she releases the arrow.`,
    a:`Elastic potential energy; it becomes kinetic energy.`,
    e:`Cung kéo căng giữ thế năng đàn hồi (elastic potential energy). Khi buông tay, thế năng đó chuyển thành động năng (kinetic energy) của mũi tên bay đi.` },
  { s:"Physics", topic:"2. Energy", sub:"Energy stores", year:9, exam:true,
    q:`What name is given to the energy stored in the movement of particles, which is greater in hotter objects?`,
    a:`Internal (thermal) energy.`,
    e:`Internal energy (nội năng, hay thermal energy — nhiệt năng) là năng lượng từ chuyển động của các hạt. Vật càng nóng, các hạt chuyển động càng mạnh → nhiều nội năng hơn.` },
  { s:"Physics", topic:"2. Energy", sub:"Energy stores", year:9, exam:true,
    q:`What name is given to energy stored inside materials such as uranium?`,
    a:`Nuclear energy.`,
    e:`Nuclear energy (năng lượng hạt nhân) được lưu giữ bên trong hạt nhân nguyên tử của một số chất như uranium.` },
  { s:"Physics", topic:"2. Energy", sub:"Energy resources", year:9, exam:true,
    q:`What name is given to a fuel formed from the dead remains of organisms over millions of years? Name three examples.`,
    a:`A fossil fuel; coal, oil and natural gas.`,
    e:`Fossil fuel (nhiên liệu hóa thạch) hình thành từ xác sinh vật cách đây hàng triệu năm: than đá, dầu mỏ và khí thiên nhiên.` },
  { s:"Physics", topic:"2. Energy", sub:"Energy resources", year:9, exam:true,
    q:`What type of energy resource are fossil fuels classed as?`,
    a:`A non-renewable resource.`,
    e:`Nhiên liệu hóa thạch là nguồn năng lượng không tái tạo (non-renewable resource). Lý do gọi như vậy: chúng mất hàng triệu năm để hình thành, nhưng con người dùng nhanh hơn rất nhiều. Fossil fuels are called non-renewable because they take millions of years to form, are used up far faster than they are made, and cannot be replaced once they have run out.` },
  { s:"Physics", topic:"2. Energy", sub:"Energy resources", year:9, exam:true,
    q:`State three renewable energy resources.`,
    a:`Wind, moving water and solar energy.`,
    e:`Renewable resource (nguồn tái tạo) không bao giờ cạn: gió, nước chảy (hydro), năng lượng Mặt Trời. Chúng được bổ sung liên tục bởi tự nhiên. Các đáp án khác cũng đúng: thủy triều (tidal), địa nhiệt (geothermal), sinh khối (biomass).` },
  { s:"Physics", topic:"2. Energy", sub:"Energy resources", year:9, exam:true,
    q:`State two non-renewable energy resources.`,
    a:`Fossil fuels (coal, oil or gas) and nuclear energy.`,
    e:`Non-renewable (không tái tạo): nhiên liệu hóa thạch và năng lượng hạt nhân — dùng hết là không có lại.` },
  { s:"Physics", topic:"2. Energy", sub:"Solar energy", year:9, exam:true,
    q:`What is the original source of the energy stored in coal?`,
    a:`The Sun.`,
    e:`Nguồn gốc của năng lượng trong than đá chính là Mặt Trời. Lý do: cây cối thời cổ đại dùng quá trình quang hợp (photosynthesis) để hấp thụ năng lượng ánh sáng Mặt Trời và tích trong thân. Ancient plants used the Sun's light to make food and stored that energy in their bodies; when the plants died they were buried and, over millions of years, became coal — so the energy in coal originally came from the Sun.` },
  { s:"Physics", topic:"2. Energy", sub:"Conservation of energy", year:9, exam:true,
    q:`State the law of conservation of energy.`,
    a:`Energy cannot be created or destroyed, only transferred.`,
    e:`Định luật bảo toàn năng lượng: năng lượng không tự sinh ra hay mất đi, nó chỉ chuyển từ dạng/kho này sang kho khác.` },
  { s:"Physics", topic:"2. Energy", sub:"Energy transfer", year:9, exam:true,
    q:`When energy is wasted in a transfer, how is it usually carried away?`,
    a:`By heating the surroundings, and by sound.`,
    e:`Năng lượng hao phí thường thoát ra môi trường bằng cách làm nóng xung quanh, và đôi khi bằng âm thanh. Năng lượng này bị "dissipated" — tản ra.` },
  { s:"Physics", topic:"2. Energy", sub:"Dissipate", year:9, exam:true,
    q:`What name is given to wasted energy that has spread out into the surroundings so it is no longer useful?`,
    a:`Dissipated energy.`,
    e:`Dissipate = tản ra, lan rộng (năng lượng đã bị dissipated). Năng lượng hao phí lan vào môi trường và không còn dùng được nữa.` },
  { s:"Physics", topic:"2. Energy", sub:"Efficiency", year:9, exam:true,
    q:`What does the efficiency of an energy transfer tell you?`,
    a:`How much of the energy is transferred usefully.`,
    e:`Efficiency (hiệu suất) so sánh năng lượng có ích với tổng năng lượng đưa vào. Hiệu suất càng cao → hao phí càng ít.` },
  { s:"Physics", topic:"2. Energy", sub:"Efficiency calculation", year:9, exam:true,
    q:`A lamp is supplied with 100 J of electrical energy and gives out 20 J as light. Calculate its efficiency as a percentage.`,
    a:`20%.`,
    e:`Hiệu suất = năng lượng có ích ÷ tổng năng lượng × 100 = 20 ÷ 100 × 100 = 20%. Phần còn lại (80 J) hao phí dưới dạng nhiệt.` },
  { s:"Physics", topic:"2. Energy", sub:"Efficiency calculation", year:9, exam:true,
    q:`A motor is given 500 J of energy and transfers 350 J usefully. Calculate its efficiency as a percentage.`,
    a:`70%.`,
    e:`Hiệu suất = 350 ÷ 500 × 100 = 70%. Có 150 J bị hao phí (chủ yếu thành nhiệt và âm thanh).` },
  { s:"Physics", topic:"2. Energy", sub:"Energy transfer", year:9, exam:true,
    q:`The electricity we use cannot be stored. From what is it generated?`,
    a:`From energy resources (wind, water, the Sun, fossil fuels or nuclear).`,
    e:`Điện được tạo ra (generated) từ các nguồn năng lượng khác như gió, nước, Mặt Trời, nhiên liệu hóa thạch hoặc hạt nhân. Lý do nó không thể được "lưu trữ" trực tiếp: electricity is not a store of energy, it is a way of transferring energy, so it cannot be saved up — it has to be generated at the moment it is needed. Pin chỉ lưu hóa năng (chemical energy), không lưu điện.` },
  { s:"Physics", topic:"2. Energy", sub:"Energy transfer diagram", year:9, exam:true,
    q:`A man pushes his daughter on a swing, then stops pushing. Name the two things that gradually transfer the swing's energy away.`,
    a:`Friction and air resistance.`,
    e:`Hai thứ làm năng lượng của xích đu mất dần là ma sát (friction) ở trục và lực cản không khí (air resistance). Lý do xích đu dừng lại: each swing, a little energy is transferred away by friction at the pivot and by air resistance, and this energy is dissipated (tản ra) into the surroundings as heat and sound. Năng lượng của xích đu giảm dần nên nó đu thấp hơn và cuối cùng dừng hẳn.` },
  { s:"Physics", topic:"2. Energy", sub:"Energy transfer diagram", year:9, exam:true,
    q:`Humans get their energy from food. Name the original source of the energy in that food.`,
    a:`The Sun.`,
    e:`Năng lượng đi qua chuỗi: Mặt Trời → thực vật (quang hợp) → động vật/con người ăn vào. Gốc gác luôn là Mặt Trời.` },
  { s:"Physics", topic:"2. Energy", sub:"Word problem", year:9, exam:true,
    q:`Nam burns 1000 J of chemical energy in a torch. The torch produces 150 J of light. State how much energy is wasted and how it is most likely transferred.`,
    a:`850 J wasted, mostly by heating.`,
    e:`Tổng 1000 J − có ích 150 J = 850 J hao phí. Phần hao phí chủ yếu làm nóng đèn pin và môi trường xung quanh. Bảo toàn năng lượng vẫn đúng — năng lượng không mất, chỉ chuyển dạng.` },
  { s:"Physics", topic:"2. Energy", sub:"Word problem", year:9, exam:true,
    q:`Mai stretches a rubber band and lets go so it flies across the room. What energy store does the elastic potential energy become?`,
    a:`A kinetic energy store.`,
    e:`Thế năng đàn hồi chuyển thành động năng (kinetic energy store). Lý do: dây cao su bị kéo căng tích thế năng đàn hồi (elastic potential energy). When Mai lets go, the stretched band returns to its natural shape and transfers its stored elastic potential energy into a kinetic store, so the band gains movement energy and flies across the room. Bạn Mai vừa làm một thí nghiệm chuyển hóa năng lượng đó!` },
  { s:"Physics", topic:"2. Energy", sub:"Application", year:9, exam:true,
    q:`Early steam engines had an efficiency of only a few per cent. State whether most of the energy from the coal was transferred usefully or wastefully.`,
    a:`Wastefully.`,
    e:`Hiệu suất chỉ vài phần trăm nghĩa là chỉ vài % năng lượng dùng có ích để làm máy chạy; hơn 90% hao phí thành nhiệt, tản ra môi trường xung quanh. Máy hơi nước cũ rất "phí" năng lượng.` },
  { s:"Physics", topic:"2. Energy", sub:"GPE factors", year:9, exam:true,
    q:`Name two factors that affect the amount of gravitational potential energy stored in an object.`,
    a:`Its mass and how high it has been raised.`,
    e:`GPE phụ thuộc khối lượng (nặng hơn → nhiều GPE) và độ cao (cao hơn → nhiều GPE), cùng với cường độ trường hấp dẫn g. Hai yếu tố đầu là đáp án chính.` }
);

/* ----- CLUSTER 2: Energy stores and transfers ----- */
const PHX_ENERGY = { title:`Energy stores and transfers`, html:`<p>Energy is never created or destroyed; it is only transferred from one store to another. A roller coaster car at the top of the track holds a large amount of gravitational potential energy. As it rushes downhill, this energy is transferred to a kinetic store, so the car speeds up. Not all of the energy ends up where it is wanted: some is wasted, transferred by friction and air resistance to heat the surroundings and to make sound. The efficiency of a machine compares the useful energy it transfers with the total energy supplied to it.</p><p><i>[Figure: a roller coaster track with the car at the top labelled "gravitational potential store" and the car at the bottom labelled "kinetic store"; small wavy arrows leaving the track are labelled "energy wasted by heating and sound".]</i></p>` };
window.QBANK.push(
  { s:"Physics", topic:"2. Energy", sub:"Passage", year:9, exam:true, p:PHX_ENERGY,
    q:`Name the energy store that the roller coaster car has when it is at the top of the track.`,
    a:`A gravitational potential energy store.`,
    e:`Ở đỉnh đường ray, xe lượn ở trên cao nên có thế năng hấp dẫn (gravitational potential energy) lớn.` },
  { s:"Physics", topic:"2. Energy", sub:"Passage", year:9, exam:true, p:PHX_ENERGY,
    q:`Using the passage, name the energy store that the car's gravitational potential energy is transferred to as it rushes downhill.`,
    a:`A kinetic store.`,
    e:`Khi xe lượn đi xuống, thế năng hấp dẫn được chuyển thành động năng (kinetic store). Lý do: as the car drops to a lower point, its gravitational potential energy decreases, and this energy is transferred into a kinetic store, so the car speeds up. Đây là một sự chuyển kho năng lượng (energy transfer) — năng lượng vẫn được bảo toàn, chỉ đổi dạng.` },
  { s:"Physics", topic:"2. Energy", sub:"Passage", year:9, exam:true, p:PHX_ENERGY,
    q:`The passage says some energy is wasted. State two ways this wasted energy is carried away from the roller coaster.`,
    a:`By heating the surroundings, and by sound.`,
    e:`Năng lượng hao phí bị tản ra (dissipated) bằng cách làm nóng môi trường và tạo ra âm thanh. Năng lượng vẫn được bảo toàn, chỉ là không còn hữu ích.` }
);

/* ===================== CHAPTER 3: Speed & motion graphs ===================== */
window.QBANK.push(
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Definition", year:9, exam:false,
    q:`What name is given to how far an object travels in a certain time?`,
    a:`Speed.`,
    e:`Speed (tốc độ) cho biết quãng đường đi được trong một khoảng thời gian. Tính bằng cách lấy quãng đường chia cho thời gian.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Formula", year:9, exam:false,
    q:`Write down the formula linking speed, distance and time.`,
    a:`speed = distance ÷ time.`,
    e:`Công thức: speed = distance ÷ time. Có thể đổi thành distance = speed × time, hoặc time = distance ÷ speed.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Units", year:9, exam:false,
    q:`State three common units used for speed.`,
    a:`m/s, km/h and mph.`,
    e:`Đơn vị tốc độ tùy theo đơn vị quãng đường và thời gian: mét trên giây (m/s), kilômét trên giờ (km/h), dặm trên giờ (mph). Trong khoa học (đơn vị SI) ta thường dùng m/s.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Calculation", year:9, exam:false,
    q:`A car travels 200 km in 4 hours. Calculate its average speed. Give your answer in km/h.`,
    a:`50 km/h.`,
    e:`speed = distance ÷ time = 200 km ÷ 4 h = 50 km/h. Đừng quên ghi đơn vị nhé!` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Calculation", year:9, exam:false,
    q:`A horse and rider cover 54 km in 9 hours. Calculate the mean speed. Give your answer in km/h.`,
    a:`6 km/h.`,
    e:`speed = 54 km ÷ 9 h = 6 km/h. Đây là tốc độ trung bình (mean speed) cho cả hành trình.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Calculation", year:9, exam:false,
    q:`A runner travels 100 m in 20 s. Calculate the runner's speed in m/s.`,
    a:`5 m/s.`,
    e:`speed = distance ÷ time = 100 m ÷ 20 s = 5 m/s.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Calculation", year:9, exam:false,
    q:`A cyclist rides at 8 m/s for 15 s. Calculate how far the cyclist travels. Give your answer in metres.`,
    a:`120 m.`,
    e:`distance = speed × time = 8 m/s × 15 s = 120 m. Khi tìm quãng đường, đổi công thức thành distance = speed × time.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Calculation", year:9, exam:false,
    q:`A train travels 240 km at a steady speed of 80 km/h. Calculate how long the journey takes. Give your answer in hours.`,
    a:`3 hours.`,
    e:`time = distance ÷ speed = 240 km ÷ 80 km/h = 3 h.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Mean speed", year:9, exam:false,
    q:`State how you work out the mean (average) speed for a whole journey.`,
    a:`Divide the total distance travelled by the total time taken.`,
    e:`Mean speed = tổng quãng đường ÷ tổng thời gian. Nó tính cả lúc dừng nghỉ, nên thường nhỏ hơn tốc độ nhanh nhất.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Unit conversion", year:9, exam:false,
    q:`State how you convert a speed in m/s into km/h.`,
    a:`Multiply by 3.6.`,
    e:`1000 m = 1 km, 3600 s = 1 h. Đổi m/s sang km/h: chia cho 1000 (ra km) rồi nhân 3600 (giây trong một giờ), gọn lại là ×3.6.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Unit conversion", year:9, exam:false,
    q:`Convert 50 km/h into m/s. Give your answer to 1 decimal place.`,
    a:`13.9 m/s.`,
    e:`Đổi km/h sang m/s: ×1000 rồi ÷3600. 50 × 1000 ÷ 3600 = 13.888... ≈ 13.9 m/s.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Unit conversion", year:9, exam:false,
    q:`The fastest human can run at 44 km/h. Convert this speed to m/s. Give your answer to 1 decimal place.`,
    a:`12.2 m/s.`,
    e:`44 km/h ÷ 3.6 = 12.22... ≈ 12.2 m/s. (Cách dài: 44 × 1000 ÷ 3600.)` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Displacement", year:9, exam:false,
    q:`What name is given to the distance in a straight line between an object and its starting point?`,
    a:`Displacement.`,
    e:`Displacement (độ dịch chuyển) là khoảng cách thẳng từ điểm xuất phát đến vị trí hiện tại — khác với quãng đường thực sự đi (có thể quanh co).` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Distance-time graphs", year:9, exam:false,
    q:`On a distance-time graph, state what a steep line shows.`,
    a:`A high speed.`,
    e:`Trên đồ thị quãng đường-thời gian, đường càng dốc → vật chuyển động càng nhanh (tốc độ càng lớn). Đường thoải → chậm.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Distance-time graphs", year:9, exam:false,
    q:`On a distance-time graph, state what a horizontal (flat) line shows.`,
    a:`The object is stationary.`,
    e:`Đường nằm ngang trên đồ thị distance-time nghĩa là quãng đường không tăng → vật đang đứng yên (not moving).` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Gradient", year:9, exam:false,
    q:`On a distance-time graph, state what the gradient of a line represents.`,
    a:`The speed of the object.`,
    e:`Độ dốc (gradient) của đường trên đồ thị distance-time chính là tốc độ. Gradient = thay đổi quãng đường ÷ thay đổi thời gian.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Gradient", year:9, exam:false,
    q:`On a distance-time graph a line rises by 40 m over a time of 2 s. Calculate the speed. Give your answer in m/s.`,
    a:`20 m/s.`,
    e:`gradient = vertical change ÷ horizontal change = 40 m ÷ 2 s = 20 m/s. Gradient của đồ thị distance-time là tốc độ.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Relative speed", year:9, exam:false,
    q:`You walk at 2 m/s towards the front of a train that is moving at 50 m/s. Calculate your speed relative to the ground outside. Give your answer in m/s.`,
    a:`52 m/s.`,
    e:`Đi cùng chiều tàu → cộng tốc độ: 50 + 2 = 52 m/s so với mặt đất. Nếu đi ngược về phía sau tàu thì 50 − 2 = 48 m/s.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Relative speed", year:9, exam:false,
    q:`Two trains travel directly towards each other, each at 100 km/h. Calculate how fast they are moving relative to each other. Give your answer in km/h.`,
    a:`200 km/h.`,
    e:`Hai vật tiến lại gần nhau → cộng tốc độ: 100 + 100 = 200 km/h. Đó là tốc độ tương đối (relative speed) giữa hai tàu.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Speed-time graphs", year:9, exam:false,
    q:`On a speed-time graph, state what a horizontal line shows.`,
    a:`A constant (steady) speed.`,
    e:`Trên đồ thị speed-time, đường nằm ngang → tốc độ không đổi. Lưu ý: đồ thị này khác đồ thị distance-time.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Speed-time graphs", year:9, exam:false,
    q:`On a speed-time graph, state what a sloping line shows.`,
    a:`The object is accelerating.`,
    e:`Đường dốc trên đồ thị speed-time nghĩa là vật đang thay đổi tốc độ: dốc lên = tăng tốc, dốc xuống = giảm tốc. Cả hai đều là "accelerating".` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Acceleration", year:9, exam:false,
    q:`What name is given to how quickly an object is speeding up or slowing down, and what are its units?`,
    a:`Acceleration; units m/s².`,
    e:`Acceleration (gia tốc) cho biết tốc độ thay đổi nhanh thế nào. Đơn vị là mét trên giây trên giây (m/s²). Gia tốc 5 m/s² nghĩa là mỗi giây tốc độ tăng thêm 5 m/s.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Speed-time graphs", year:9, exam:false,
    q:`A vehicle travels at a steady 15 m/s for 10 s. Calculate the distance it covers. Give your answer in metres.`,
    a:`150 m.`,
    e:`distance = speed × time = 15 m/s × 10 s = 150 m. Quãng đường này cũng chính là diện tích hình nằm dưới đường trên đồ thị speed-time. On a speed-time graph the distance travelled equals the area under the line — here the line is flat, so the area is a rectangle of width 10 s and height 15 m/s, which gives 150 m.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Word problem", year:9, exam:false,
    q:`Mr Wong travels 70 km by train. The journey takes 1.5 hours, including a 10-minute stop. Calculate his mean speed for the whole journey, including the stop. Give your answer in km/h to 1 decimal place.`,
    a:`46.7 km/h.`,
    e:`Mean speed dùng tổng thời gian (kể cả lúc dừng): 70 km ÷ 1.5 h = 46.67 ≈ 46.7 km/h.` },
  { s:"Physics", topic:"3. Speed & motion graphs", sub:"Word problem", year:9, exam:false,
    q:`Lan walks 1.5 km to school in 30 minutes. Calculate her average speed. Give your answer in km/h.`,
    a:`3 km/h.`,
    e:`30 phút = 0.5 giờ. speed = distance ÷ time = 1.5 km ÷ 0.5 h = 3 km/h. Nhớ đổi phút sang giờ trước khi tính nhé.` }
);

/* ===================== CHAPTER 4: Machines & moments ===================== */
window.QBANK.push(
  { s:"Physics", topic:"4. Machines & moments", sub:"Machine", year:9, exam:false,
    q:`In physics, what name is given to a device, such as a lever or a ramp, that makes it easier to move something?`,
    a:`A machine.`,
    e:`Machine (máy / máy đơn giản — simple machine) giúp ta làm việc với lực dễ hơn — như đòn bẩy, ròng rọc, mặt phẳng nghiêng.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Lever", year:9, exam:false,
    q:`What name is given to a simple machine made of a long bar that turns around a pivot?`,
    a:`A lever.`,
    e:`Lever (đòn bẩy) là một thanh dài quay quanh một điểm tựa. Đẩy xuống một đầu thì đầu kia nâng vật lên.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Fulcrum", year:9, exam:false,
    q:`What name is given to the fixed point about which a lever turns? State another name for it.`,
    a:`A fulcrum; it is also called a pivot.`,
    e:`Fulcrum (điểm tựa) là điểm cố định mà đòn bẩy quay quanh. Còn gọi là pivot.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Lever parts", year:9, exam:false,
    q:`On a lever, what name is given to the force you apply, and what name is given to the weight being moved?`,
    a:`The effort and the load.`,
    e:`Trên đòn bẩy: effort = lực em tác dụng, load = vật/trọng lượng cần nâng. Điểm tựa là fulcrum.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Force multiplier", year:9, exam:false,
    q:`State when a lever acts as a force multiplier.`,
    a:`When the effort is further from the pivot than the load.`,
    e:`Force multiplier (đòn bẩy nhân lực): khi tay cầm (effort) xa điểm tựa hơn vật (load) → lực nhỏ tạo ra lực lớn hơn lên vật. Đổi lại, tay phải di chuyển xa hơn.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Distance multiplier", year:9, exam:false,
    q:`State what a distance multiplier does.`,
    a:`A large effort makes the load move a greater distance.`,
    e:`Distance multiplier (đòn bẩy nhân khoảng cách): lực lớn (effort) đi đoạn ngắn, làm vật (load) di chuyển xa hơn — ví dụ cánh tay của em khi ném bóng.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Ramp", year:9, exam:false,
    q:`When a ramp is used instead of lifting an object straight up, what happens to the size of the force needed?`,
    a:`It decreases — a smaller force is needed.`,
    e:`Dùng mặt phẳng nghiêng (ramp) thì lực cần thiết giảm — chỉ cần một lực nhỏ hơn. Lý do nó "dễ hơn": pushing an object up a gentle slope needs less force than lifting it straight up. Đánh đổi (trade-off) là vật phải di chuyển quãng đường dài hơn dọc theo dốc, nên tổng công (work = force × distance) vẫn như cũ. Dốc càng thoải thì lực cần càng nhỏ.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Pulley", year:9, exam:false,
    q:`In a system of pulleys, what is the load shared between?`,
    a:`Several sections of rope.`,
    e:`Trong hệ ròng rọc, tải trọng (load) được chia cho nhiều đoạn dây. Lý do điều này giảm lực kéo: when the weight of the load is shared between several rope sections, each section only holds part of the load, so a smaller pulling force is needed. Đánh đổi là phải kéo dây dài hơn. Lưu ý: một ròng rọc đơn chỉ đổi hướng lực chứ không làm giảm lực.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Moment", year:9, exam:false,
    q:`What name is given to the turning effect of a force?`,
    a:`A moment.`,
    e:`Moment (mô-men lực) là tác dụng làm quay của lực — như khi em dùng cờ-lê vặn đai ốc.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Moment formula", year:9, exam:false,
    q:`Write down the formula for the moment of a force.`,
    a:`moment = force × perpendicular distance from the pivot.`,
    e:`moment = lực × khoảng cách vuông góc từ điểm tựa. Khoảng cách phải đo vuông góc (perpendicular) với lực.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Units", year:9, exam:false,
    q:`State the unit of a moment.`,
    a:`The newton metre (N m).`,
    e:`Đơn vị của mô-men lực là newton mét (N m) — vì moment = lực (N) × khoảng cách (m).` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Moment calculation", year:9, exam:false,
    q:`A spanner is 0.2 m long and a force of 20 N is applied at its end. Calculate the moment of the force. Give your answer in newton metres.`,
    a:`4 N m.`,
    e:`moment = force × distance = 20 N × 0.2 m = 4 N m.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Moment calculation", year:9, exam:false,
    q:`A force of 220 N acts at a perpendicular distance of 2 m from a pivot. Calculate the moment. Give your answer in newton metres.`,
    a:`440 N m.`,
    e:`moment = 220 N × 2 m = 440 N m.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Moment calculation", year:9, exam:false,
    q:`Minh pushes down on a lever with a force of 50 N at a distance of 1.2 m from the pivot. Calculate the moment he creates. Give your answer in newton metres.`,
    a:`60 N m.`,
    e:`moment = force × distance = 50 N × 1.2 m = 60 N m. Càng đẩy xa điểm tựa, mô-men càng lớn — nên bạn Minh cầm ở đầu xa cho dễ.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Equilibrium", year:9, exam:false,
    q:`State what is true about the moments on a lever when it is in equilibrium.`,
    a:`The clockwise moment equals the anticlockwise moment.`,
    e:`Equilibrium (cân bằng): mô-men quay theo chiều kim đồng hồ = mô-men ngược chiều kim đồng hồ. Đòn bẩy đứng yên, không quay.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Equilibrium", year:9, exam:false,
    q:`A balanced see-saw has a load creating a clockwise moment of 1800 N m. State the size of the anticlockwise moment from the effort.`,
    a:`1800 N m.`,
    e:`Khi cân bằng, hai mô-men bằng nhau. Vậy mô-men ngược chiều kim đồng hồ cũng = 1800 N m.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Equilibrium", year:9, exam:false,
    q:`On a balanced lever, a load of 400 N acts 1 m from the pivot. The effort acts 2 m from the pivot. Calculate the size of the effort. Give your answer in newtons.`,
    a:`200 N.`,
    e:`Cân bằng: effort × 2 m = 400 N × 1 m = 400 N m. Vậy effort = 400 ÷ 2 = 200 N. Khoảng cách lớn hơn nên lực nhỏ hơn — đó là lợi thế của đòn bẩy!` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Work", year:9, exam:false,
    q:`In physics, what name is given to the energy transferred when a force moves an object?`,
    a:`Work.`,
    e:`Work (công), còn gọi là work done, là năng lượng được chuyển khi một lực làm vật di chuyển. Đo bằng joule (J).` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Work formula", year:9, exam:false,
    q:`Write down the formula for work done.`,
    a:`work done = force × distance moved.`,
    e:`work = lực × quãng đường di chuyển theo hướng của lực. Đơn vị là joule (J).` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Units", year:9, exam:false,
    q:`State the unit of work.`,
    a:`The joule (J).`,
    e:`Công được đo bằng joule (J) — cùng đơn vị với năng lượng, vì công chính là năng lượng được chuyển.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Work calculation", year:9, exam:false,
    q:`A force of 50 N pulls a rope through a distance of 2 m. Calculate the work done. Give your answer in joules.`,
    a:`100 J.`,
    e:`work = force × distance = 50 N × 2 m = 100 J.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Work calculation", year:9, exam:false,
    q:`Nam pushes a box with a force of 30 N and moves it 6 m across the floor. Calculate the work he does. Give your answer in joules.`,
    a:`180 J.`,
    e:`work = force × distance = 30 N × 6 m = 180 J. Toàn bộ công này chuyển thành nhiệt do ma sát khi hộp trượt.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Work calculation", year:9, exam:false,
    q:`Lifting a block straight up needs a force of 1000 N over a distance of 1 m. Calculate the work done. Give your answer in joules.`,
    a:`1000 J.`,
    e:`work = force × distance = 1000 N × 1 m = 1000 J. Khối được nâng nên tích lũy 1000 J thế năng hấp dẫn.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Conservation", year:9, exam:false,
    q:`A machine lets you use a smaller force to lift a load. What happens to the distance that force must move?`,
    a:`It increases — the force must move a greater distance.`,
    e:`Khi máy cho phép dùng lực nhỏ hơn, lực đó phải di chuyển một quãng đường dài hơn. Lý do máy không giúp tiết kiệm năng lượng: work done = force × distance, so if the force is smaller but the distance is larger, the product (the work done) stays the same. Máy đơn giản không tạo ra năng lượng "miễn phí" — thực tế công bỏ ra còn lớn hơn một chút vì phải thắng ma sát.` },
  { s:"Physics", topic:"4. Machines & moments", sub:"Application", year:9, exam:false,
    q:`On a bottle opener, which acts further from the pivot — the effort or the load?`,
    a:`The effort.`,
    e:`Trên cái mở nắp chai, lực tác dụng (effort, tay cầm) ở xa điểm tựa hơn so với vật (load, nắp chai). Lý do nó là một force multiplier (đòn bẩy nhân lực): because the effort acts a long way from the pivot while the cap is close to it, a small effort produces a much larger force on the cap, which is enough to lever it off.` }
);

/* ===================== CHAPTER 5: Force fields, gravity & magnetism ===================== */
window.QBANK.push(
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Force field", year:9, exam:true,
    q:`In physics, what name is given to a region where a non-contact force has an effect?`,
    a:`A force field.`,
    e:`Force field (trường lực) là vùng không gian nơi một lực không tiếp xúc có tác dụng — ví dụ trường từ, trường hấp dẫn, trường điện.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Magnetic field", year:9, exam:true,
    q:`What name is given to the space around a magnet where it can affect magnetic materials or other magnets?`,
    a:`A magnetic field.`,
    e:`Magnetic field (từ trường) là vùng quanh nam châm nơi nó có thể hút vật liệu từ hoặc tác dụng lên nam châm khác.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Magnet poles", year:9, exam:true,
    q:`Name the two ends of a bar magnet.`,
    a:`The north pole and the south pole.`,
    e:`Hai đầu của nam châm thẳng gọi là cực bắc (north pole) và cực nam (south pole).` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Magnet poles", year:9, exam:true,
    q:`State the rule for what happens when magnetic poles are brought together.`,
    a:`Like poles repel; opposite poles attract.`,
    e:`Quy tắc: cùng cực (hai cực bắc, hoặc hai cực nam) thì đẩy nhau; khác cực (một bắc, một nam) thì hút nhau. (Like repel, opposite attract.)` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Magnetic field", year:9, exam:true,
    q:`State where the magnetic field of a bar magnet is strongest.`,
    a:`At the poles.`,
    e:`Từ trường mạnh nhất ở hai cực của nam châm — đó là nơi các đường sức từ gần nhau nhất.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Compass", year:9, exam:true,
    q:`What is a compass needle made of?`,
    a:`A small magnet.`,
    e:`Kim la bàn là một nam châm nhỏ. Lý do cực bắc của nó luôn chỉ hướng bắc: the Earth has its own magnetic field, and the needle, being a tiny magnet, lines itself up with that field. Cực bắc của kim (north-seeking pole) bị hút theo từ trường Trái Đất nên quay về phía bắc, giúp ta tìm phương hướng.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Earth's field", year:9, exam:true,
    q:`State one useful job that the Earth's magnetic field does.`,
    a:`It helps to protect the Earth from charged particles emitted by the Sun.`,
    e:`Từ trường của Trái Đất chắn bớt các hạt mang điện do Mặt Trời phóng ra, bảo vệ sự sống trên hành tinh.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Gravitational field", year:9, exam:true,
    q:`What name is given to the space around any object with mass where its gravity attracts other masses?`,
    a:`A gravitational field.`,
    e:`Gravitational field (trường hấp dẫn) là vùng quanh một vật có khối lượng, nơi lực hấp dẫn của nó hút các vật khác.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Gravity", year:9, exam:true,
    q:`What name is given to the force of attraction between any two objects that have mass?`,
    a:`Gravity.`,
    e:`Gravity (trọng lực / lực hấp dẫn — gravitational force) là lực hút giữa hai vật có khối lượng. Trái Đất rất lớn nên hút mọi vật về phía nó.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Field strength", year:9, exam:true,
    q:`What is the value of the gravitational field strength on the surface of the Earth?`,
    a:`About 10 N/kg.`,
    e:`Cường độ trường hấp dẫn của Trái Đất g ≈ 10 N/kg. Giá trị này có nghĩa là: the Earth's gravity pulls on every 1 kg of mass with a force of 10 N. Vậy một vật 5 kg chịu trọng lượng 5 × 10 = 50 N. Đó cũng là lý do công thức weight = mass × g.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Weight", year:9, exam:true,
    q:`What name is given to the force with which gravity pulls on an object, and what is it measured in?`,
    a:`Weight; it is measured in newtons (N).`,
    e:`Weight (trọng lượng) là lực hút của trọng lực lên vật. Đơn vị là newton (N). Khác với mass (khối lượng, đo bằng kg).` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Mass vs weight", year:9, exam:true,
    q:`What name is given to the amount of matter in an object?`,
    a:`Mass.`,
    e:`Lượng chất trong một vật gọi là khối lượng (mass), đo bằng kilôgam (kg). So sánh với weight: mass (khối lượng) là lượng chất, đo bằng kg, và luôn không đổi dù em ở Trái Đất hay Mặt Trăng. Weight (trọng lượng) thì khác — it is the force of gravity pulling on the object, measured in newtons (N), and it changes depending on the gravitational field strength g of the planet. Vậy: mass không đổi, weight thay đổi theo nơi em đứng.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Weight formula", year:9, exam:true,
    q:`Write down the formula linking weight, mass and gravitational field strength.`,
    a:`weight = mass × g.`,
    e:`weight (N) = mass (kg) × g, trong đó g là cường độ trường hấp dẫn (gravitational field strength). Trên Trái Đất g ≈ 10 N/kg.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Weight calculation", year:9, exam:true,
    q:`A Curiosity rover has a mass of 900 kg. Calculate its weight on Earth, using g = 10 N/kg. Give your answer in newtons.`,
    a:`9000 N.`,
    e:`weight = mass × g = 900 kg × 10 N/kg = 9000 N.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Weight calculation", year:9, exam:true,
    q:`The gravitational field strength on Mars is 3.7 N/kg. Calculate the weight on Mars of a 900 kg rover. Give your answer in newtons.`,
    a:`3330 N.`,
    e:`weight = mass × g = 900 kg × 3.7 N/kg = 3330 N. Trên sao Hỏa g nhỏ hơn nên cùng khối lượng nhưng nhẹ hơn.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Weight calculation", year:9, exam:true,
    q:`Mai has a mass of 45 kg. Calculate her weight on Earth, using g = 10 N/kg. Give your answer in newtons.`,
    a:`450 N.`,
    e:`weight = mass × g = 45 kg × 10 N/kg = 450 N. Khối lượng của bạn Mai vẫn là 45 kg dù đi đâu, nhưng trọng lượng thì đổi theo g.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Gravity factors", year:9, exam:true,
    q:`Name the two factors that affect the size of the gravitational force between two objects.`,
    a:`The masses of the objects and how far apart they are.`,
    e:`Lực hấp dẫn lớn hơn nếu vật có khối lượng lớn hơn, và nhỏ hơn nếu hai vật ở xa nhau hơn.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"GPE formula", year:9, exam:true,
    q:`Write down the formula for gravitational potential energy (GPE).`,
    a:`GPE = mass × height × gravitational field strength.`,
    e:`GPE (J) = mass (kg) × height (m) × g (N/kg). Vật càng nặng, càng cao thì GPE càng lớn.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"GPE calculation", year:9, exam:true,
    q:`Calculate the GPE of an 80 kg skydiver at a height of 1500 m, using g = 10 N/kg. Give your answer in joules.`,
    a:`1 200 000 J.`,
    e:`GPE = mass × height × g = 80 × 1500 × 10 = 1 200 000 J. Khi nhảy xuống, GPE này dần chuyển thành động năng.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"GPE calculation", year:9, exam:true,
    q:`A 65 kg skydiver is at a height of 2000 m. Calculate the GPE stored, using g = 10 N/kg. Give your answer in joules.`,
    a:`1 300 000 J.`,
    e:`GPE = 65 × 2000 × 10 = 1 300 000 J.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"GPE calculation", year:9, exam:true,
    q:`Nam lifts a 2 kg bag onto a shelf 1.5 m high. Calculate the GPE gained, using g = 10 N/kg. Give your answer in joules.`,
    a:`30 J.`,
    e:`GPE = mass × height × g = 2 × 1.5 × 10 = 30 J. Bạn Nam đã chuyển 30 J năng lượng vào cái túi khi nâng nó lên.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Field diagrams", year:9, exam:true,
    q:`On a field diagram, state how the strength of a field is shown.`,
    a:`By how close together the field lines are.`,
    e:`Trên sơ đồ trường lực, đường sức gần nhau → trường mạnh; đường sức thưa → trường yếu. Trường mạnh nhất ở nơi các đường sức gần nhau nhất.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Field diagrams", year:9, exam:true,
    q:`State the direction in which the field lines of the Earth's gravitational field point.`,
    a:`Towards the centre of the Earth.`,
    e:`Tất cả đường sức trường hấp dẫn của Trái Đất chỉ vào tâm Trái Đất — đó là hướng một vật nhỏ sẽ rơi.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Application", year:9, exam:true,
    q:`Astronauts who live in space for a long time find their bones become thinner and muscles waste away. Suggest why.`,
    a:`There is little gravity, so bones and muscles are used less.`,
    e:`Trong không gian gần như không có trọng lực kéo nên phi hành gia không cảm thấy trọng lượng; xương và cơ ít phải làm việc → yếu đi, mỏng đi. Nên phi hành gia phải tập thể dục mỗi ngày.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Storing energy", year:9, exam:true,
    q:`Describe two ways of increasing the gravitational potential energy stored in a bucket.`,
    a:`Lift it higher, or add more mass (make the bucket heavier).`,
    e:`GPE = mass × height × g. Muốn GPE lớn hơn: nâng cao hơn, hoặc cho thêm khối lượng vào xô.` }
);

/* ----- CLUSTER 3: Magnetism and the Earth's magnetic field ----- */
const PHX_MAGNET = { title:`Magnets and the Earth's magnetic field`, html:`<p>Every magnet has two poles, a north pole and a south pole, and is surrounded by a magnetic field — the region where it can affect magnetic materials and other magnets. When two poles are brought close, like poles repel and opposite poles attract. The field is strongest at the poles, where the field lines are drawn closest together. The Earth itself behaves like a giant bar magnet: its magnetic field stretches far out into space and helps to shield the planet from charged particles streaming from the Sun. A compass needle is a tiny magnet that lines up with the Earth's field, which is why it can be used to find direction.</p><p><i>[Figure: a bar magnet with curved field lines looping from the north pole to the south pole, the lines bunched tightly near each pole; beside it a small compass with its needle pointing along a field line.]</i></p>` };
window.QBANK.push(
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Passage", year:9, exam:true, p:PHX_MAGNET,
    q:`Using the passage, state what happens when the north pole of one magnet is brought close to the north pole of another.`,
    a:`They repel each other.`,
    e:`Cùng cực (hai cực bắc) thì đẩy nhau (like poles repel). Đây là quy tắc cơ bản về từ cực: like poles repel, opposite poles attract.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Passage", year:9, exam:true, p:PHX_MAGNET,
    q:`The figure shows the field lines bunched tightly near the poles. State what this tells you about the magnetic field there.`,
    a:`The magnetic field is strongest at the poles.`,
    e:`Đường sức gần nhau → từ trường mạnh. Vì thế từ trường mạnh nhất ở hai cực của nam châm — nơi các đường sức gần nhau nhất.` },
  { s:"Physics", topic:"5. Force fields, gravity & magnetism", sub:"Passage", year:9, exam:true, p:PHX_MAGNET,
    q:`Using the passage, name one useful job done by the Earth's magnetic field.`,
    a:`It helps to shield the planet from charged particles streaming from the Sun.`,
    e:`Từ trường Trái Đất chắn bớt các hạt mang điện từ Mặt Trời, bảo vệ hành tinh. Nó cũng giúp kim la bàn chỉ hướng.` }
);

/* ===================== CHAPTER 6: Electricity & magnetism ===================== */
window.QBANK.push(
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Static electricity", year:9, exam:true,
    q:`State what causes static electricity.`,
    a:`Rubbing two different insulating materials together.`,
    e:`Static electricity (tĩnh điện) sinh ra khi cọ xát hai vật liệu cách điện khác nhau, làm điện tích tích tụ lại. Đó là lý do em bị giật nhẹ khi chạm tay nắm cửa kim loại.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Atom structure", year:9, exam:true,
    q:`State where electrons are found in an atom and what charge they have.`,
    a:`Around the nucleus; they have a negative charge.`,
    e:`Electron mang điện tích âm, chuyển động quanh hạt nhân ở trung tâm. Hạt nhân chứa proton (dương) và neutron (không điện).` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Atom structure", year:9, exam:true,
    q:`In a neutral atom, what is true about the numbers of protons and electrons?`,
    a:`They are equal.`,
    e:`Trong một nguyên tử trung hòa, số proton bằng số electron. Lý do nguyên tử không có điện tích tổng: each proton carries one positive charge and each electron carries one negative charge, so when their numbers are equal the positive and negative charges cancel out exactly. Vì thế phần lớn nguyên tử trung hòa về điện (no overall charge).` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Charging by rubbing", year:9, exam:true,
    q:`When two insulating materials are rubbed together, which particles are transferred?`,
    a:`Electrons.`,
    e:`Khi cọ xát hai vật liệu cách điện, các hạt được chuyển đi là electron. Lý do chỉ có điện tích âm di chuyển: electrons can move from one material to the other, but protons are locked inside the nucleus and cannot move. Vật nhận thêm electron → tích điện âm; vật mất electron → tích điện dương.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Charging by rubbing", year:9, exam:true,
    q:`A rod is rubbed with a cloth and ends up with more electrons than before. State the charge the rod now has.`,
    a:`An overall negative charge.`,
    e:`Vật nhận thêm electron (điện tích âm) → tích điện âm. Tấm vải mất electron sẽ tích điện dương, bằng đúng độ lớn.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Charge interaction", year:9, exam:true,
    q:`State the rule for the forces between two charged objects.`,
    a:`Like charges repel; opposite charges attract.`,
    e:`Hai vật cùng dấu điện (cùng dương hoặc cùng âm) thì đẩy nhau, khác dấu thì hút nhau — giống quy tắc của cực nam châm.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Electric field", year:9, exam:true,
    q:`What name is given to the space around a charged object where it has an effect on other charges?`,
    a:`An electric field.`,
    e:`Electric field (điện trường) là vùng quanh vật tích điện, nơi nó tác dụng lực lên điện tích khác. Trường mạnh nhất ở gần vật.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Application", year:9, exam:true,
    q:`A girl touches a static-electricity machine and her hair stands out. What type of charge does each hair carry?`,
    a:`The same charge.`,
    e:`Mỗi sợi tóc đều nhận cùng một loại điện tích. Lý do tóc dựng đứng và xòe ra: like charges repel, so because every hair carries the same charge, the hairs all push each other away. Các sợi tóc đẩy nhau ra xa nhất có thể nên dựng lên và xòe rộng. Vui mà cũng là vật lý đó!` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Current", year:9, exam:true,
    q:`What name is given to a flow of electrons around a circuit?`,
    a:`An electric current.`,
    e:`Dòng điện (electric current) là dòng chuyển động của các electron quanh mạch điện.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Circuit", year:9, exam:true,
    q:`State the two things an electric current needs in order to flow.`,
    a:`A complete circuit and a source such as a cell.`,
    e:`Dòng điện chỉ chạy khi: (1) mạch kín hoàn chỉnh, và (2) có nguồn (pin hoặc bộ nguồn — power pack) để "đẩy" dòng điện đi quanh mạch.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Measuring current", year:9, exam:true,
    q:`Name the instrument that measures electric current, state how it is connected, and state the unit of current.`,
    a:`An ammeter, in series; unit the ampere (A).`,
    e:`Ampe kế (ammeter) đo dòng điện, mắc nối tiếp (in series) trong mạch. Đơn vị dòng điện là ampe (A).` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Voltage", year:9, exam:true,
    q:`Name the instrument that measures voltage, state how it is connected, and state the unit of voltage.`,
    a:`A voltmeter, in parallel; unit the volt (V).`,
    e:`Vôn kế (voltmeter) đo hiệu điện thế, mắc song song (in parallel) qua linh kiện. Đơn vị là vôn (V).` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Series circuit", year:9, exam:true,
    q:`In a series circuit, state what is true about the current at different points.`,
    a:`The current is the same everywhere in the circuit.`,
    e:`Trong mạch nối tiếp (series), chỉ có một vòng dây nên dòng điện ở mọi điểm đều như nhau.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Series circuit", year:9, exam:true,
    q:`A series circuit has two bulbs. One bulb is removed and the gap is left open. What happens to the other bulb?`,
    a:`It goes off.`,
    e:`Bóng còn lại tắt. Lý do: mạch nối tiếp (series) chỉ có một vòng dây duy nhất. Removing one bulb leaves a gap, so the circuit is no longer complete; with a broken circuit no current can flow, so the other bulb goes off too. Đèn dây "noel" kiểu cũ hỏng một bóng là cả dây tắt cũng vì lý do này.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Parallel circuit", year:9, exam:true,
    q:`What name is given to a circuit with branches that split apart and join up again?`,
    a:`A parallel circuit.`,
    e:`Mạch song song (parallel) có các nhánh tách ra rồi nhập lại. Mỗi nhánh có thể bật/tắt riêng, và nếu một nhánh hỏng các nhánh khác vẫn chạy.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Parallel circuit", year:9, exam:true,
    q:`In a parallel circuit, state what is true about the voltage across each branch.`,
    a:`It is the same as the voltage of the cell.`,
    e:`Trong mạch song song, hiệu điện thế qua mỗi nhánh đều bằng hiệu điện thế mà nguồn (pin) cung cấp.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Conductors", year:9, exam:true,
    q:`What metal are the wires in circuits usually made of?`,
    a:`Copper.`,
    e:`Dây điện trong mạch thường làm bằng đồng (copper). Lý do chọn đồng: copper is a very good electrical conductor with a low resistance, so an electric current can flow through it very easily. Dòng điện gặp ít cản trở nên ít năng lượng bị hao phí trong dây.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Resistance", year:9, exam:true,
    q:`What name is given to a measure of how difficult it is for electric current to flow through something?`,
    a:`Resistance.`,
    e:`Resistance (điện trở) cho biết dòng điện khó chạy qua một vật đến mức nào. Điện trở càng cao → dòng điện càng nhỏ.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Resistance units", year:9, exam:true,
    q:`State the unit of resistance and the symbol used for it.`,
    a:`The ohm, symbol Ω.`,
    e:`Điện trở đo bằng ohm, ký hiệu Ω (chữ Hy Lạp omega).` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Resistance factors", year:9, exam:true,
    q:`State two factors of a wire that affect its resistance.`,
    a:`Its length and its thickness.`,
    e:`Điện trở của dây phụ thuộc: chiều dài (dài hơn → trở cao hơn), độ dày (mỏng hơn → trở cao hơn), và loại kim loại làm dây. Bất kỳ hai yếu tố nào ở trên đều được chấp nhận.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Ohm's law", year:9, exam:true,
    q:`Write down the formula linking voltage, current and resistance.`,
    a:`voltage = current × resistance.`,
    e:`voltage (V) = current (A) × resistance (Ω). Có thể đổi công thức thành resistance = voltage ÷ current, hoặc current = voltage ÷ resistance.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Ohm's law calculation", year:9, exam:true,
    q:`A current of 2 A flows through a circuit with a resistance of 5 Ω. Calculate the voltage needed. Give your answer in volts.`,
    a:`10 V.`,
    e:`voltage = current × resistance = 2 A × 5 Ω = 10 V.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Ohm's law calculation", year:9, exam:true,
    q:`Calculate the voltage needed to make a 5 A current flow through a circuit with a resistance of 20 Ω. Give your answer in volts.`,
    a:`100 V.`,
    e:`voltage = current × resistance = 5 A × 20 Ω = 100 V.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Ohm's law calculation", year:9, exam:true,
    q:`A bulb has a voltage of 10 V across it and a current of 0.5 A through it. Calculate its resistance. Give your answer in ohms.`,
    a:`20 Ω.`,
    e:`resistance = voltage ÷ current = 10 V ÷ 0.5 A = 20 Ω.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Ohm's law calculation", year:9, exam:true,
    q:`A component has a current of 3 A through it when the voltage is 18 V. Calculate its resistance. Give your answer in ohms.`,
    a:`6 Ω.`,
    e:`resistance = voltage ÷ current = 18 V ÷ 3 A = 6 Ω.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Electromagnet", year:9, exam:true,
    q:`What name is given to a coil of wire that becomes magnetic when an electric current flows through it?`,
    a:`An electromagnet.`,
    e:`Nam châm điện (electromagnet) là cuộn dây có dòng điện chạy qua → tạo từ trường giống nam châm thẳng. Tắt dòng điện thì hết từ tính.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Electromagnet", year:9, exam:true,
    q:`State three ways of increasing the strength of an electromagnet.`,
    a:`More coils, more current, or add an iron core.`,
    e:`Tăng độ mạnh nam châm điện: thêm số vòng dây, tăng dòng điện, hoặc đặt lõi sắt (magnetic core) bên trong cuộn dây.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Electromagnet", year:9, exam:true,
    q:`What happens to an electromagnet when the current is switched off?`,
    a:`It loses its magnetism.`,
    e:`Khi tắt dòng điện, nam châm điện (electromagnet) mất hết từ tính. Đây là điểm khác với nam châm thẳng: a bar magnet is a permanent magnet and stays magnetic all the time, but an electromagnet is only magnetic while a current flows through its coil. Đó cũng là ưu điểm của nam châm điện — nó có thể bật/tắt từ tính theo ý muốn.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Motor effect", year:9, exam:true,
    q:`What name is given to the force produced when a wire carrying a current is placed in a magnetic field?`,
    a:`The motor effect.`,
    e:`Motor effect: khi dây có dòng điện đặt trong từ trường, hai từ trường tương tác và dây chịu một lực. Đây là nguyên lý của động cơ điện.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Electric motor", year:9, exam:true,
    q:`In a simple electric motor, what part spins inside the magnetic field?`,
    a:`A coil of wire.`,
    e:`Bộ phận quay bên trong từ trường của động cơ điện đơn giản là một cuộn dây (coil of wire). A simple electric motor is made of a coil of wire placed inside a magnetic field, which is provided by permanent magnets or an electromagnet; when a current passes through the coil, the motor effect makes the coil spin. Dòng điện qua cuộn dây tạo ra lực làm nó quay tròn.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Electric motor", year:9, exam:true,
    q:`State two ways to make an electric motor spin faster.`,
    a:`Increase the current in the coil, or use a stronger magnetic field.`,
    e:`Cho động cơ quay nhanh hơn: tăng dòng điện trong cuộn, dùng từ trường mạnh hơn, hoặc tăng số vòng dây (more turns). Bất kỳ hai cách nào đều được chấp nhận.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Resistor", year:9, exam:true,
    q:`State what a resistor is used for in a circuit.`,
    a:`To control the size of the current.`,
    e:`Resistor (điện trở - linh kiện) làm dòng điện khó chạy hơn, dùng để giảm hoặc điều chỉnh cường độ dòng điện trong mạch.` }
);

/* ----- CLUSTER 4: Electricity, circuits and Ohm's law ----- */
const PHX_ELEC = { title:`Electric current and circuits`, html:`<p>An electric current is a flow of electrons around a circuit. For a current to flow, two things are needed: a complete, unbroken circuit and a source of energy such as a cell to push the electrons around. The current is measured with an ammeter joined into the circuit in series, while the voltage across a component is measured with a voltmeter joined in parallel. Some materials, called conductors, let current pass through easily; copper wire is a good example. Resistance is a measure of how hard it is for current to flow, and it is linked to voltage and current by the relationship voltage = current × resistance.</p><p><i>[Figure: a simple series circuit drawn with standard symbols — a cell, a switch, a lamp and an ammeter in the loop, and a voltmeter connected across the lamp.]</i></p>` };
window.QBANK.push(
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Passage", year:9, exam:true, p:PHX_ELEC,
    q:`Using the passage, name the instrument used to measure the current and state how it must be connected.`,
    a:`An ammeter, connected in series in the circuit.`,
    e:`Ampe kế (ammeter) đo dòng điện và phải mắc nối tiếp (in series) trong mạch để dòng điện chạy qua nó.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Passage", year:9, exam:true, p:PHX_ELEC,
    q:`The switch in the figure is opened so the circuit is broken. What happens to the current in the circuit?`,
    a:`No current can flow.`,
    e:`Khi mạch bị hở, không có dòng điện chạy nữa. Lý do đèn tắt: as the passage says, a current needs a complete, unbroken circuit to flow. Opening the switch breaks the circuit, so no current can flow and the lamp goes out. Mạch phải kín hoàn toàn thì electron mới đi vòng quanh được.` },
  { s:"Physics", topic:"6. Electricity & magnetism", sub:"Passage", year:9, exam:true, p:PHX_ELEC,
    q:`A current of 3 A flows through the lamp when the voltage across it is 12 V. Using the relationship in the passage, calculate the resistance of the lamp. Give your answer in ohms.`,
    a:`4 Ω.`,
    e:`Từ voltage = current × resistance → resistance = voltage ÷ current = 12 V ÷ 3 A = 4 Ω.` }
);

/* ===================== CHAPTER 7: Heat, differences & waves ===================== */
window.QBANK.push(
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Heating", year:9, exam:true,
    q:`State how energy is transferred when a hot drink cools down.`,
    a:`By heating, from the drink to the cooler air.`,
    e:`Năng lượng truyền bằng cách "heating" (đốt nóng/truyền nhiệt), từ vật nóng sang vật lạnh hơn. Đồ uống nóng truyền nhiệt cho không khí mát hơn xung quanh.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Temperature differences", year:9, exam:true,
    q:`State the direction in which energy flows when there is a temperature difference.`,
    a:`From the hotter object to the cooler object.`,
    e:`Nhiệt luôn truyền từ nơi nóng sang nơi lạnh hơn — không bao giờ ngược lại một cách tự nhiên.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Latent heat", year:9, exam:true,
    q:`What name is given to the energy needed to break the bonds between particles when a substance melts or evaporates?`,
    a:`Latent heat.`,
    e:`Latent heat (nhiệt ẩn) là năng lượng dùng để phá vỡ liên kết giữa các hạt khi nóng chảy/bay hơi. Khi đông đặc/ngưng tụ, năng lượng này được trả lại.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Latent heat", year:9, exam:true,
    q:`While ice is melting, energy is being transferred to it. What is this energy used to do?`,
    a:`To break the bonds between the particles.`,
    e:`Năng lượng cấp cho đá đang tan được dùng để phá vỡ liên kết giữa các hạt. Lý do nhiệt độ giữ nguyên ở 0 °C: while the ice melts, the incoming energy goes into breaking the bonds between particles (this is the latent heat — nhiệt ẩn) rather than into making the particles move faster. Vì nhiệt độ phụ thuộc tốc độ chuyển động của hạt, mà năng lượng không dùng cho việc đó, nên nhiệt độ đứng yên ở 0 °C cho đến khi đá tan hết.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Specific heat capacity", year:9, exam:true,
    q:`What name is given to the energy needed to raise the temperature of 1 kg of a substance by 1 °C?`,
    a:`Specific heat capacity.`,
    e:`Specific heat capacity (nhiệt dung riêng) là năng lượng cần để làm 1 kg một chất nóng thêm 1 °C. Nước có giá trị này cao.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Specific heat capacity", year:9, exam:true,
    q:`Joyah heats water in one beaker and the same mass of soil in another with the same energy. Which is hotter after 10 minutes?`,
    a:`The soil.`,
    e:`Sau 10 phút, đất nóng hơn nước. Lý do: soil has a lower specific heat capacity than water, so for the same mass and the same energy supplied, the soil's temperature rises by more. Nước có nhiệt dung riêng (specific heat capacity) cao, cần nhiều năng lượng hơn để tăng cùng số độ, nên nó nóng lên chậm hơn.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Convection", year:9, exam:true,
    q:`What name is given to a flow of liquid or gas caused by part of it being heated or cooled more than the rest?`,
    a:`A convection current.`,
    e:`Convection current (dòng đối lưu) là dòng chất lỏng/khí: phần nóng nở ra, nhẹ hơn, bốc lên; phần lạnh chìm xuống → tạo dòng tuần hoàn.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Convection", year:9, exam:true,
    q:`When a fluid is warmed, what happens to its density?`,
    a:`It decreases — the fluid becomes less dense.`,
    e:`Khi chất lưu nóng lên, mật độ (density) của nó giảm — nó trở nên loãng hơn (less dense). Lý do điều này quan trọng cho đối lưu: warming makes the fluid expand, so it becomes less dense than the cooler fluid around it; the warmer, less dense fluid then rises while cooler, denser fluid sinks. Sự chênh lệch mật độ này chính là thứ tạo ra dòng đối lưu (convection currents).` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Sea breeze", year:9, exam:true,
    q:`During the day, in which direction does a sea breeze blow?`,
    a:`From the sea towards the land.`,
    e:`Ban ngày, gió biển (sea breeze) thổi từ biển vào đất liền. Lý do: during the day the land heats up faster than the sea, so the warm air above the land becomes less dense and rises. Không khí mát hơn, đặc hơn từ phía biển tràn vào thay chỗ — luồng không khí di chuyển từ biển vào đất liền đó chính là gió biển.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Potential difference", year:9, exam:true,
    q:`State what the potential difference (voltage) across a component shows.`,
    a:`It shows how much energy is transferred by that component.`,
    e:`Potential difference (hiệu điện thế) cho biết năng lượng được chuyển bởi linh kiện đó. Còn gọi là voltage.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Potential difference", year:9, exam:true,
    q:`During a lightning strike, what happens to the air between a cloud and the ground?`,
    a:`It conducts electricity.`,
    e:`Khi có tia sét, không khí giữa đám mây và mặt đất dẫn điện. Lý do liên quan đến hiệu điện thế: a charged cloud builds up a very large potential difference compared with the ground (or another cloud). Khi hiệu điện thế đủ lớn — có thể tới 100 triệu vôn — nó "ép" được không khí, vốn là chất cách điện, trở thành dẫn điện. Dòng điện khổng lồ phóng qua không khí đó chính là tia sét mà ta nhìn thấy.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Waves", year:9, exam:true,
    q:`State what all waves transfer, and what they do not transfer.`,
    a:`Waves transfer energy; they do not transfer matter.`,
    e:`Sóng (wave) truyền năng lượng nhưng không truyền vật chất. Các hạt chỉ dao động tại chỗ, không bị mang đi cùng sóng.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Sound waves", year:9, exam:true,
    q:`What name is given to vibrations in the particles of a solid, liquid or gas that our ears detect?`,
    a:`A sound wave.`,
    e:`Sóng âm (sound wave) là dao động của các hạt trong chất rắn, lỏng hoặc khí. Tai ta thu nhận dao động này và "nghe" thành âm thanh.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Light", year:9, exam:true,
    q:`State one important way in which light is different from sound.`,
    a:`Light can travel through a vacuum, but sound cannot.`,
    e:`Ánh sáng truyền được qua chân không — empty space (như từ Mặt Trời tới Trái Đất). Âm thanh thì cần môi trường có hạt — không có không khí thì không nghe được.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Reflection", year:9, exam:true,
    q:`What name is given to a wave bouncing off a surface instead of passing through it?`,
    a:`Reflection.`,
    e:`Reflection (phản xạ) là sóng dội ngược lại khi gặp bề mặt (sóng bị reflected). Tiếng vang (echo) là âm thanh phản xạ; gương cho ảnh là ánh sáng phản xạ.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Refraction", year:9, exam:true,
    q:`What name is given to a light ray changing direction as it passes from one medium to another?`,
    a:`Refraction.`,
    e:`Refraction (khúc xạ) là hiện tượng tia sáng đổi hướng khi đi từ môi trường này sang môi trường khác — như khi nhìn cây bút bị "gãy" trong cốc nước.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Proportion", year:9, exam:true,
    q:`State what it means to say two variables are directly proportional.`,
    a:`When one variable doubles, the other also doubles.`,
    e:`Tỉ lệ thuận (directly proportional): biến này gấp đôi thì biến kia cũng gấp đôi; nếu một biến bằng 0 thì biến kia cũng bằng 0. Đồ thị là đường thẳng đi qua gốc tọa độ (0,0).` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Proportion", year:9, exam:true,
    q:`Current-voltage graphs for a resistor are straight lines through the origin. State what relationship this shows.`,
    a:`It shows that current is directly proportional to voltage.`,
    e:`Đồ thị dòng điện theo hiệu điện thế là đường thẳng qua gốc → dòng điện tỉ lệ thuận với hiệu điện thế. Tăng gấp đôi V thì I cũng gấp đôi.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Inverse proportion", year:9, exam:true,
    q:`State what it means to say two variables are inversely proportional.`,
    a:`When one variable doubles, the other halves.`,
    e:`Tỉ lệ nghịch (inversely proportional): biến này gấp đôi thì biến kia giảm một nửa. Ví dụ với một lượng điện tích cố định, thời gian gấp đôi thì dòng điện giảm một nửa.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Models", year:9, exam:true,
    q:`What type of model can be touched or built as a real object?`,
    a:`A physical model.`,
    e:`Loại mô hình có thể sờ hoặc dựng được như một vật thật gọi là physical model (mô hình vật chất) — ví dụ mô hình quả cầu - thanh nối (ball-and-stick) của phân tử. So sánh với abstract model: an abstract model cannot be touched — it only exists as an idea, a computer program, a formula or a diagram. Vậy khác biệt chính là: physical model sờ/dựng được, abstract model thì không.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Eclipse", year:9, exam:true,
    q:`State what happens during a lunar eclipse.`,
    a:`The Moon moves into the Earth's shadow.`,
    e:`Nguyệt thực (lunar eclipse): Mặt Trăng đi vào vùng bóng của Trái Đất. Trái Đất chắn ánh sáng Mặt Trời không tới được Mặt Trăng.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Cause and effect", year:9, exam:true,
    q:`State what Newton's Third Law tells you about forces.`,
    a:`Forces always come in equal and opposite pairs.`,
    e:`Định luật 3 Newton: lực luôn xuất hiện theo cặp. Nếu một vật tác dụng lực lên vật thứ hai, vật thứ hai tác dụng lại một lực bằng độ lớn và ngược chiều. Em đẩy tường thì tường đẩy lại em.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Cause and effect", year:9, exam:true,
    q:`What name is given to a link in which a change in one variable actually causes a change in another?`,
    a:`A causal link.`,
    e:`Mối liên hệ trong đó thay đổi của biến này thực sự GÂY RA thay đổi của biến kia gọi là causal link (mối liên hệ nhân quả). So sánh với correlation: a correlation just means two things change together, which may only be a coincidence. Một causal link mạnh hơn — nó khẳng định một biến là nguyên nhân của biến kia. Bài học quan trọng: "đi cùng nhau" (correlation) chưa chắc là "nguyên nhân" (causation).` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Word problem", year:9, exam:true,
    q:`Lan takes an ice cube out of the freezer into a warm room. What happens to the ice cube?`,
    a:`It melts.`,
    e:`Viên đá tan ra. Lý do, xét theo chênh lệch nhiệt độ (temperature difference): the ice cube is colder than the room, and energy always flows from a hotter place to a cooler one, so energy is transferred by heating from the warm room into the colder ice. Nhiệt độ viên đá tăng dần tới 0 °C rồi nó bắt đầu tan. Bạn Lan vừa quan sát một quá trình truyền nhiệt đó.` },
  { s:"Physics", topic:"7. Heat, differences & waves", sub:"Word problem", year:9, exam:true,
    q:`On a sunny beach the sand feels much hotter than the sea. Which has the lower specific heat capacity?`,
    a:`The sand.`,
    e:`Cát có nhiệt dung riêng (specific heat capacity) thấp hơn nước. Lý do cát nóng hơn biển: sand has a much lower specific heat capacity than water, so when both receive the same amount of energy from the Sun, the sand's temperature rises by far more than the sea's. Vì thế cát có thể bỏng chân trong khi nước biển vẫn mát dễ chịu!` }
);

/* ----- CLUSTER 5: The electromagnetic spectrum ----- */
const PHX_EM = { title:`The electromagnetic spectrum`, html:`<p>The electromagnetic spectrum is the whole family of waves that all travel at the speed of light and can pass through empty space. The spectrum is split into seven bands, arranged in order of wavelength and frequency. From the longest wavelength and lowest frequency to the shortest wavelength and highest frequency, the bands are radio waves, microwaves, infrared, visible light, ultraviolet, X-rays and gamma rays. Visible light is the only band our eyes can detect. The other bands have many everyday uses: radio waves carry broadcasts, microwaves cook food and carry phone signals, infrared is given out by warm objects and is used in television remote controls, while X-rays and gamma rays carry the most energy and can be dangerous.</p><p><i>[Figure: a horizontal chart of the electromagnetic spectrum showing the seven bands from radio waves on the left, through microwaves, infrared, visible light, ultraviolet and X-rays, to gamma rays on the right; an arrow below shows wavelength decreasing and frequency increasing from left to right.]</i></p>` };
